package app.org.apache.roller.weblogger.business.runnable;

public abstract class RollerTaskWithLeasing extends RollerTask { private static Log log = LogFactory . getLog ( RollerTaskWithLeasing . class ) ; protected static final int DEFAULT_LEASE_MINS = 30 ; public abstract void runTask ( ) throws WebloggerException ; public final void run ( ) { ThreadManager mgr = WebloggerFactory . getWeblogger ( ) . getThreadManager ( ) ; boolean lockAcquired = false ; try { log . debug ( getName ( ) + ": Attempting to acquire lease" ) ; lockAcquired = mgr . registerLease ( this ) ; if ( lockAcquired ) { log . debug ( getName ( ) + ": Lease acquired, running task" ) ; this . runTask ( ) ; } else { log . debug ( getName ( ) + ": Lease NOT acquired, cannot continue" ) ; return ; } } catch ( Exception ex ) { log . error ( getName ( ) + ": Unexpected exception" , ex ) ; } finally { if ( lockAcquired ) { log . debug ( getName ( ) + ": Attempting to release lease" ) ; boolean lockReleased = mgr . unregisterLease ( this ) ; if ( lockReleased ) { log . debug ( getName ( ) + ": Lease released, task finished" ) ; } else { log . debug ( getName ( ) + ": Lease NOT released, some kind of problem" ) ; } } WebloggerFactory . getWeblogger ( ) . release ( ) ; } } }